INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (62, 1, -416.5, 1, 190805, 3.414, 0.0, "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", "カリン", 1000001, 1, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (62, 1, -416.5, 1, 190805, 3.099, 0.0, "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", "カリン", 1000002, 2, "ミッションをクリアして、\n報酬をゲットしましょう！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (63, 1, -416.5, 1, 190805, 2.801, 0.0, "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", "カリン", 1000003, 3, "受け取ることができる\n報酬があるようです\n確認してみてください");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (63, 1, -416.5, 2, 190805, 0.0, 0.0, "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", "カリン", 1000004, 4, "報酬がもらえますよ！\nチェックしてみてください");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (64, 1, -363.0, 2, 190805, 2.12, 0.0, "2025/01/31 12:00:00", 1, "2030/01/01 14:59:59", "カリン", 1000005, 5, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (64, 1, -363.0, 1, 190805, 1.68, 0.0, "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", "カリン", 1000006, 6, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (64, 1, -363.0, 2, 190805, 2.33, 0.0, "2025/01/31 12:00:00", 1, "2030/01/01 14:59:59", "カリン", 1000007, 7, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10201, -285.0, 3, 133701, 5.18, -6.0, "2025/01/31 12:00:00", 7, "2030/01/01 14:59:59", "ラビリスタ", 1020101, 101, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10201, -285.0, 1, 133901, 8.77, -2.0, "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", "クリスティーナ", 1020102, 201, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10201, -285.0, 6, 133801, 15.5, 0.0, "2025/01/31 12:00:00", 1, "2030/01/01 14:59:59", "ネネカ", 1020103, 301, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10202, -285.0, 2, 134301, 9.061, 0.0, "2025/02/28 12:00:00", 5, "2030/01/01 14:59:59", "ランファ", 1020201, 101, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10202, -285.0, 1, 134401, 7.699, 0.0, "2025/02/28 12:00:00", 2, "2030/01/01 14:59:59", "チカ", 1020202, 201, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10203, -285.0, 1, 134601, 8.595, 0.0, "2025/03/31 12:00:00", 2, "2030/01/01 14:59:59", "アオイ", 1020301, 101, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10203, -285.0, 1, 134501, 7.758, 0.0, "2025/03/31 12:00:00", 2, "2030/01/01 14:59:59", "クローチェ", 1020302, 201, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10204, -285.0, 2, 132302, 7.0, 0.0, "2025/04/30 12:00:00", 6, "2030/01/01 14:59:59", "ルイズマリー", 1020401, 101, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10204, -285.0, 1, 132402, 7.904, 0.0, "2025/04/30 12:00:00", 2, "2030/01/01 14:59:59", "イロハ", 1020402, 201, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10204, -285.0, 4, 132502, 8.487, 0.0, "2025/04/30 12:00:00", 2, "2030/01/01 14:59:59", "ソノ", 1020403, 301, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10205, -285.0, 1, 134901, 8.763, 0.0, "2025/05/31 12:00:00", 2, "2030/01/01 14:59:59", "カノン", 1020502, 101, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10205, -285.0, 1, 134801, 6.417, 0.0, "2025/05/31 12:00:00", 3, "2030/01/01 14:59:59", "ツムギ", 1020503, 201, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10206, -285.0, 3, 135001, 10.335, 0.0, "2025/06/30 12:00:00", 7, "2030/01/01 14:59:59", "エリス", 1020601, 101, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10206, -285.0, 2, 135101, 6.281, 0.0, "2025/06/30 12:00:00", 4, "2030/01/01 14:59:59", "シェフィ", 1020602, 201, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10206, -285.0, 1, 135201, 12.244, 0.0, "2025/06/30 12:00:00", 2, "2030/01/01 14:59:59", "プレシア", 1020603, 301, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10207, -285.0, 2, 135301, 6.339, 0.0, "2025/07/31 12:00:00", 8, "2030/01/01 14:59:59", "クリア", 1020701, 101, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10207, -285.0, 7, 135401, 8.184, 0.0, "2025/07/31 12:00:00", 9, "2030/01/01 14:59:59", "アネモネ", 1020702, 201, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10208, -285.0, 9, 129101, 3.906, 0.0, "2025/08/31 12:00:00", 2, "2030/01/01 14:59:59", "アイラ", 1020801, 101, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10208, -285.0, 1, 129201, 14.465, 0.0, "2025/08/31 12:00:00", 2, "2030/01/01 14:59:59", "シナツ", 1020802, 201, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10208, -285.0, 4, 100101, 8.662, 0.0, "2025/08/31 12:00:00", 3, "2030/01/01 14:59:59", "ヒヨリ", 1020803, 301, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10208, -285.0, 1, 100301, 10.915, 0.0, "2025/08/31 12:00:00", 3, "2030/01/01 14:59:59", "レイ", 1020804, 401, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10209, -285.0, 1, 135802, 6.042, 0.0, "2025/09/30 12:00:00", 7, "2030/01/01 14:59:59", "ユキノ", 1020901, 101, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10209, -285.0, 4, 135903, 9.402, 0.0, "2025/09/30 12:00:00", 1, "2030/01/01 14:59:59", "サツキ", 1020902, 201, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10209, -285.0, 8, 136902, 8.16, 0.0, "2025/09/30 12:00:00", 1, "2030/01/01 14:59:59", "ルルィ", 1020903, 301, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10210, -285.0, 3, 137401, 5.0, 0.0, "2025/10/31 12:00:00", 2, "2030/01/01 14:59:59", "カスミ", 1021001, 101, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10210, -285.0, 4, 136001, 8.12, 0.0, "2025/10/31 12:00:00", 1, "2030/01/01 14:59:59", "アラクネ", 1021002, 201, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10210, -285.0, 4, 136202, 6.386, 0.0, "2025/10/31 12:00:00", 2, "2030/01/01 14:59:59", "ナーナ", 1021003, 301, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10211, -285.0, 3, 136402, 7.438, 0.0, "2025/11/30 12:00:00", 4, "2030/01/01 14:59:59", "ユイ", 1021101, 101, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10211, -285.0, 1, 136302, 8.35, 0.0, "2025/11/30 12:00:00", 5, "2030/01/01 14:59:59", "ミソラ", 1021102, 201, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10212, -285.0, 1, 136501, 5.0, 0.0, "2025/12/31 12:00:00", 2, "2030/01/01 14:59:59", "シズル", 1021201, 101, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10212, -285.0, 1, 137902, 5.25, 0.0, "2025/12/31 12:00:00", 2, "2030/01/01 14:59:59", "リノ", 1021202, 201, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10212, -285.0, 1, 106801, 7.5, 0.0, "2025/12/31 12:00:00", 2, "2030/01/01 14:59:59", "ラビリスタ", 1021203, 301, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10213, -285.0, 1, 126501, 8.204, 0.0, "2026/01/31 12:00:00", 2, "2030/01/01 14:59:59", "ライラエル", 1021301, 101, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10213, -285.0, 1, 129701, 7.176, 0.0, "2026/01/31 12:00:00", 2, "2030/01/01 14:59:59", "ネフィ＝ネラ", 1021302, 201, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10213, -285.0, 1, 133101, 8.602, 0.0, "2026/01/31 12:00:00", 5, "2030/01/01 14:59:59", "ヴァイオレット", 1021303, 301, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10213, -285.0, 1, 138101, 10.14, 0.0, "2026/02/06 12:00:00", 3, "2030/01/01 14:59:59", "ライラエル", 1021304, 102, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10213, -285.0, 1, 138201, 10.152, 0.0, "2026/02/06 12:00:00", 7, "2030/01/01 14:59:59", "ネフィ＝ネラ", 1021305, 202, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10213, -285.0, 4, 138001, 9.688, 0.0, "2026/02/06 12:00:00", 3, "2030/01/01 14:59:59", "ヴァイオレット", 1021306, 302, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10213, -285.0, 2, 138301, 5.928, 0.0, "2026/02/12 12:00:00", 1, "2030/01/01 14:59:59", "ペコリーヌ", 1021307, 401, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10214, -285.0, 4, 138702, 9.19, 0.0, "2026/02/28 12:00:00", 2, "2030/01/01 14:59:59", "ワカナ", 1021401, 101, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？");
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (61, 10214, -285.0, 1, 138802, 8.724, 0.0, "2026/02/28 12:00:00", 3, "2030/01/01 14:59:59", "シオリ", 1021402, 201, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！");
